<?phpdeclare(strict_types=1);/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}/***ReportingModulePage*Generateandexportvariousreports*/session_start();require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/auth_helper.php';/Checkauthenticationif(!AuthHelper::validateSession()){header('Location:'.url('login.php'));exit;}$pageTitle='Laporan&Statistik';include__DIR__.'/../includes/components/header.php';?><divclass="container-fluidpy-4"><!--PageHeader--><divclass="d-flexjustify-content-betweenalign-items-centermb-4"><div><h2class="mb-1"><iclass="fasfa-chart-bartext-primaryme-2"></i>Laporan&Statistik</h2><pclass="text-mutedmb-0">Generatelaporandananalisisdatapersonil</p></div></div><!--ReportTypes--><divclass="rowmb-4"><divclass="col-md-4"><divclass="cardh-100"><divclass="card-body"><h5class="card-title"><iclass="fasfa-userstext-primaryme-2"></i>RingkasanPersonil</h5><pclass="card-texttext-muted">Laporanringkasanpersonilberdasarkanunsurdanbagian.</p><divclass="d-flexgap-2"><buttonclass="btnbtn-primary"onclick="generateReport('personil_summary')"><iclass="fasfa-eyeme-2"></i>Lihat</button><buttonclass="btnbtn-outline-success"onclick="exportReport('personil_summary','csv')"><iclass="fasfa-downloadme-2"></i>CSV</button></div></div></div></div><divclass="col-md-4"><divclass="cardh-100"><divclass="card-body"><h5class="card-title"><iclass="fasfa-chart-pietext-infome-2"></i>Demografi</h5><pclass="card-texttext-muted">Analisisdemografiberdasarkanusia,jeniskelamin,danpendidikan.</p><buttonclass="btnbtn-infotext-white"onclick="generateReport('demographic')"><iclass="fasfa-eyeme-2"></i>LihatDemografi</button></div></div></div><divclass="col-md-4"><divclass="cardh-100"><divclass="card-body"><h5class="card-title"><iclass="fasfa-sitemaptext-successme-2"></i>StrukturOrganisasi</h5><pclass="card-texttext-muted">Laporanpersonilberdasarkanstrukturorganisasi.</p><buttonclass="btnbtn-success"onclick="generateReport('organizational')"><iclass="fasfa-eyeme-2"></i>LihatStruktur</button></div></div></div></div><!--ReportContent--><divclass="cardshadow-sm"id="reportContainer"style="display:none;"><divclass="card-headerbg-whitepy-3"><divclass="d-flexjustify-content-betweenalign-items-center"><h5class="mb-0"id="reportTitle">Laporan</h5><divclass="d-flexgap-2"><buttonclass="btnbtn-smbtn-outline-primary"onclick="exportCurrentReport('json')"><iclass="fasfa-codeme-2"></i>JSON</button><buttonclass="btnbtn-smbtn-outline-success"onclick="exportCurrentReport('csv')"><iclass="fasfa-file-csvme-2"></i>CSV</button><buttonclass="btnbtn-smbtn-outline-danger"onclick="exportCurrentReport('pdf')"><iclass="fasfa-file-pdfme-2"></i>PDF</button></div></div></div><divclass="card-body"id="reportContent"><!--Reportcontentwillbeloadedhere--></div></div><!--QuickStats--><divclass="rowmt-4"><divclass="col-12"><h5class="mb-3">StatistikCepat</h5></div><divclass="col-md-3"><divclass="cardbg-primarytext-white"><divclass="card-body"><h6class="card-title">TotalPersonil</h6><h2class="mb-0"id="statTotal">-</h2><small>Seluruhinstansi</small></div></div></div><divclass="col-md-3"><divclass="cardbg-successtext-white"><divclass="card-body"><h6class="card-title">POLRI</h6><h2class="mb-0"id="statPolri">-</h2><small>PersonilPOLRI</small></div></div></div><divclass="col-md-3"><divclass="cardbg-infotext-white"><divclass="card-body"><h6class="card-title">ASN</h6><h2class="mb-0"id="statAsn">-</h2><small>AparaturSipilNegara</small></div></div></div><divclass="col-md-3"><divclass="cardbg-warningtext-white"><divclass="card-body"><h6class="card-title">P3K</h6><h2class="mb-0"id="statP3k">-</h2><small>PegawaiP3K</small></div></div></div></div></div><script>letcurrentReport=null;letcurrentReportType=null;/Loadquickstatsonpageloaddocument.addEventListener('DOMContentLoaded',function(){loadQuickStats();});/LoadquickstatisticsasyncfunctionloadQuickStats(){try{constresponse=awaitfetch(api_url('unsur_stats.php'));constdata=awaitresponse.json();if(data.success){conststats=data.data.statistics;document.getElementById('statTotal').textContent=stats.total_personil;document.getElementById('statPolri').textContent=stats.polri_count;document.getElementById('statAsn').textContent=stats.asn_count;document.getElementById('statP3k').textContent=stats.p3k_count||0;}}catch(error){console.error('Errorloadingstats:',error);}}/GeneratereportasyncfunctiongenerateReport(type){currentReportType=type;consttitles={'personil_summary':'RingkasanPersonil','demographic':'LaporanDemografi','organizational':'StrukturOrganisasi'};document.getElementById('reportTitle').textContent=titles[type]||'Laporan';document.getElementById('reportContent').innerHTML='<divclass="text-centerpy-4"><divclass="spinner-bordertext-primary"></div><pclass="mt-2">Memuatlaporan...</p></div>';document.getElementById('reportContainer').style.display='block';try{constresponse=awaitfetch(`../api/report_api.php?action=${type}`);constdata=awaitresponse.json();if(data.success){currentReport=data.data;renderReport(type,data.data);}else{document.getElementById('reportContent').innerHTML=`<divclass="alertalert-danger">${data.message}</div>`;}}catch(error){console.error('Errorgeneratingreport:',error);document.getElementById('reportContent').innerHTML='<divclass="alertalert-danger">Gagalmemuatlaporan</div>';}}/RenderreportbasedontypefunctionrenderReport(type,data){lethtml='';switch(type){case'personil_summary':html=renderPersonilSummary(data);break;case'demographic':html=renderDemographicReport(data);break;case'organizational':html=renderOrganizationalReport(data);break;default:html='<divclass="alertalert-info">Pilihjenislaporan</div>';}document.getElementById('reportContent').innerHTML=html;}/RenderpersonilsummaryfunctionrenderPersonilSummary(data){constsummary=data.summary;lethtml=`<divclass="rowmb-4"><divclass="col-md-6"><h6>TotalPersonil:${summary.total_personil}</h6><divclass="progressmb-3"style="height:25px;"><divclass="progress-barbg-primary"style="width:${(summary.type_distribution.polri/summary.total_personil*100).toFixed(1)}%">POLRI:${summary.type_distribution.polri}</div></div><divclass="progressmb-3"style="height:25px;"><divclass="progress-barbg-info"style="width:${(summary.type_distribution.asn/summary.total_personil*100).toFixed(1)}%">ASN:${summary.type_distribution.asn}</div></div><divclass="progress"style="height:25px;"><divclass="progress-barbg-warning"style="width:${(summary.type_distribution.p3k/summary.total_personil*100).toFixed(1)}%">P3K:${summary.type_distribution.p3k}</div></div></div><divclass="col-md-6"><h6>GenderDistribution</h6><p>Laki-laki:${summary.gender_distribution.male}|Perempuan:${summary.gender_distribution.female}</p></div></div><divclass="table-responsive"><tableclass="tabletable-striped"><thead><tr><th>Unsur</th><th>Bagian</th><thclass="text-end">Total</th><thclass="text-end">POLRI</th><thclass="text-end">ASN</th><thclass="text-end">P3K</th></tr></thead><tbody>`;data.by_bagian.forEach(row=>{html+=`<tr><td>${escapeHtml(row.unsur||'-')}</td><td>${escapeHtml(row.bagian||'-')}</td><tdclass="text-end"><strong>${row.total}</strong></td><tdclass="text-end">${row.polri}</td><tdclass="text-end">${row.asn}</td><tdclass="text-end">${row.p3k}</td></tr>`;});html+=`</tbody></table></div>`;returnhtml;}/RenderdemographicreportfunctionrenderDemographicReport(data){lethtml='<divclass="row">';/Agedistributionhtml+=`<divclass="col-md-6"><h6class="mb-3">DistribusiUsia</h6><tableclass="tabletable-sm"><thead><tr><th>KelompokUsia</th><thclass="text-end">Jumlah</th><thclass="text-end">POLRI</th><thclass="text-end">ASN</th></tr></thead><tbody>`;data.age_distribution.forEach(row=>{html+=`<tr><td>${row.age_group}</td><tdclass="text-end">${row.count}</td><tdclass="text-end">${row.polri}</td><tdclass="text-end">${row.asn}</td></tr>`;});html+='</tbody></table></div>';/Educationdistributionhtml+=`<divclass="col-md-6"><h6class="mb-3">TingkatPendidikan</h6><tableclass="tabletable-sm"><thead><tr><th>Pendidikan</th><thclass="text-end">Jumlah</th></tr></thead><tbody>`;data.education_distribution.forEach(row=>{html+=`<tr><td>${escapeHtml(row.education)}</td><tdclass="text-end">${row.count}</td></tr>`;});html+='</tbody></table></div></div>';returnhtml;}/RenderorganizationalreportfunctionrenderOrganizationalReport(data){lethtml=`<pclass="text-muted">TotalRecords:${data.total_records}</p><divclass="table-responsive"><tableclass="tabletable-stripedtable-sm"><thead><tr><th>Nama</th><th>NRP/NIP</th><th>Unsur</th><th>Bagian</th><th>Jabatan</th><th>Pangkat</th><th>Jenis</th></tr></thead><tbody>`;data.personil.forEach(row=>{html+=`<tr><td>${escapeHtml(row.nama)}</td><td>${row.nrp||row.nip||'-'}</td><td>${escapeHtml(row.nama_unsur||'-')}</td><td>${escapeHtml(row.nama_bagian||'-')}</td><td>${escapeHtml(row.nama_jabatan||'-')}</td><td>${escapeHtml(row.nama_pangkat||'-')}</td><td>${escapeHtml(row.jenis_pegawai||'-')}</td></tr>`;});html+='</tbody></table></div>';returnhtml;}/ExportreportfunctionexportReport(type,format){if(format==='csv'){window.open(`../api/report_api.php?action=export&type=${type}&format=csv`,'_blank');}else{window.open(`../api/report_api.php?action=${type}`,'_blank');}}/ExportcurrentreportfunctionexportCurrentReport(format){if(!currentReportType){alert('Pilihlaporanterlebihdahulu');return;}if(format==='csv'){window.open(`../api/report_api.php?action=export&type=${currentReportType}&format=csv`,'_blank');}elseif(format==='json'){window.open(`../api/report_api.php?action=${currentReportType}`,'_blank');}else{alert('ExportPDFakansegeratersedia');}}/HelperfunctionfunctionescapeHtml(text){if(!text)return'-';constdiv=document.createElement('div');div.textContent=text;returndiv.innerHTML;}</script><?phpinclude__DIR__.'/../includes/components/footer.php';?>
